boot.artifact:
// inferred-not-tested:样式必须进入 document.head;按 color_mode 换文件(auto 版的 dark/light 规则被 @media 包裹,dataset.theme 覆盖无效)
const file = data.color_mode === 'light' ? 'github-markdown-light.css' : data.color_mode === 'dark' ? 'github-markdown-dark.css' : 'github-markdown.min.css';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/github-markdown-css@5.9.0/' + file; document.head.appendChild(css);
const el = document.getElementById('markdown'); el.className = 'markdown-body';
el.style.padding = `${data.padding ?? 32}px`; el.innerHTML = data.html;

boot.widget:
// widget 零足迹:CSS 与 .markdown-body 都落 shadowRoot;按 color_mode 换文件
const file = data.color_mode === 'light' ? 'github-markdown-light.css' : data.color_mode === 'dark' ? 'github-markdown-dark.css' : 'github-markdown.min.css';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/github-markdown-css@5.9.0/' + file;
const el = document.createElement('article'); el.className = 'markdown-body';
el.style.padding = `${data.padding ?? 32}px`; el.innerHTML = data.html;
shadowRoot.append(css, el);

